public class Account {
 private String address;
 private int balance;
 private int nonce;
 private String codeHash;

 public Account(String address, int balance, int nonce, String codeHash) {
 this.address = address;
 this.balance = balance;
 this.nonce = nonce;
 this.codeHash = codeHash;
 }

 @Override
 public String toString() {
 return String.format("Account %s: balance=%d, nonce=%d, codeHash=%s", address, balance, nonce, codeHash);
 }

 // Example usage:
 public static void main(String[] args) {
 Account account = new Account("0x1234567890abcdef", 0, 0, null);
 System.out.println(account);
 account.balance = 10;
 System.out.println(account);
 }
}
